#include <stdio.h>
#include <stdarg.h>
#include <string.h>

int my_sprintf(char *buf, size_t sz, const char *fmt, ...) {
    va_list args;
    va_start(args, fmt);
    size_t pos = 0;
    while (*fmt && pos < sz - 1) {
        if (*fmt == '%') {
            fmt++;
            switch (*fmt) {
            case 'd': {
                int val = va_arg(args, int);
                pos += snprintf(buf + pos, sz - pos, "%d", val);
                break;
            }
            case 's': {
                char *val = va_arg(args, char *);
                pos += snprintf(buf + pos, sz - pos, "%s", val);
                break;
            }
            case 'x': {
                unsigned int val = va_arg(args, unsigned int);
                pos += snprintf(buf + pos, sz - pos, "%x", val);
                break;
            }
            case '%':
                buf[pos++] = '%';
                break;
            }
        } else {
            buf[pos++] = *fmt;
        }
        fmt++;
    }
    buf[pos] = '\0';
    va_end(args);
    return pos;
}

int main(void) {
    {
        char buf[64];
        my_sprintf(buf, sizeof(buf), "%d", 42);
        printf("%s\n", buf);
    }
    {
        char buf[64];
        my_sprintf(buf, sizeof(buf), "Hello %s", "world");
        printf("%s\n", buf);
    }
    {
        char buf[64];
        my_sprintf(buf, sizeof(buf), "0x%x", 255);
        printf("%s\n", buf);
    }
    {
        char buf[64];
        my_sprintf(buf, sizeof(buf), "100%%");
        printf("%s\n", buf);
    }
    {
        char buf[128];
        my_sprintf(buf, sizeof(buf), "n=%d s=%s x=%x %%", 10, "test", 255);
        printf("%d\n", (strstr(buf, "n=10") != NULL) ? 1 : 0);
        printf("%d\n", (strstr(buf, "s=test") != NULL) ? 1 : 0);
        printf("%d\n", (strstr(buf, "x=ff") != NULL) ? 1 : 0);
    }
    return 0;
}

