 * Fonction variadique simple avec va_list
 * =========================================================== */
void print_ints(int count, ...) {
    va_list args;
    va_start(args, count);
    for (int i = 0; i < count; i++)
        printf("%d ", va_arg(args, int));
    printf("\n");
    va_end(args);
}

/* == VOTRE EXERCICE =========================================
 * Implémenter my_printf avec %d, %s, %x, %%
 * =========================================================== */

void my_printf(const char *fmt, ...) {
    va_list args;
    va_start(args, fmt);
    while (*fmt) {
        if (*fmt == '%') {
            fmt++;
            switch (*fmt) {
            case 'd': printf("%d", va_arg(args, int)); break;
            case 's': printf("%s", va_arg(args, char *)); break;
            case 'x': printf("%x", va_arg(args, unsigned int)); break;
            case '%': putchar('%'); break;
            }
        } else {
            putchar(*fmt);
        }
        fmt++;
    }
    va_end(args);
}

